// Extract messaging event from Facebook payload
const body = $input.first().json.body;
const entries = body.entry || [];
const results = [];

for (const entry of entries) {
  const messaging = entry.messaging || [];
  for (const event of messaging) {
    if (event.message && event.message.text) {
      results.push({
        json: {
          senderId: event.sender.id,
          recipientId: event.recipient.id,
          messageId: event.message.mid,
          messageText: event.message.text,
          timestamp: event.timestamp
        }
      });
    }
  }
}

if (results.length === 0) {
  // Non-text event (postback, delivery receipt, etc.) - stop processing
  return [];
}

return results;

// Deduplication using message.mid
// In production, replace this with a Redis/DB lookup.
// This in-memory approach works per-execution only as a structural placeholder.
// For true dedup, use an external store (Redis SET with TTL, or a Google Sheets "ProcessedMessages" tab).

const messageId = $input.first().json.messageId;

// Placeholder: In a real deployment, check if messageId exists in your store.
// If it does, return empty to stop processing.
// For now, we pass through and mark it for downstream awareness.

return [
  {
    json: {
      ...$input.first().json,
      deduplicationNote: 'In production, check messageId against external store before proceeding.',
      isDuplicate: false
    }
  }
];

// Normalize the AI classifier output
const raw = ($input.first().json.message?.content || $input.first().json.choices?.[0]?.message?.content || '').trim().toLowerCase();

const validIntents = ['order_track', 'style_inquiry', 'order_create', 'human_support', 'product_inquiry', 'faq', 'greeting', 'unknown'];

let intent = 'unknown';
for (const valid of validIntents) {
  if (raw.includes(valid)) {
    intent = valid;
    break;
  }
}

// Pass through original message data
const prev = $('Dedup Check (message.mid)').first().json;

return [
  {
    json: {
      ...prev,
      intent: intent,
      rawClassification: raw
    }
  }
];

// Branch 1: Greeting - Direct Reply
const msg = $('Normalize Intent').first().json.messageText.toLowerCase();
let replyText = '';

if (msg.includes('bye') || msg.includes('goodbye') || msg.includes('see you')) {
  replyText = 'Goodbye! Thanks for chatting with us. Come back anytime! 👋';
} else if (msg.includes('thank') || msg.includes('thx') || msg.includes('appreciate')) {
  replyText = "You're welcome! Happy to help. Is there anything else I can do for you?";
} else if (msg.includes('ok') || msg.includes('got it') || msg.includes('sure') || msg.includes('perfect')) {
  replyText = 'Great! Let me know if you need anything else.';
} else {
  replyText = "Hello! Welcome to our store! 🛍️\n\nI can help you with:\n• Browsing products\n• Style recommendations\n• Answering questions\n• Placing orders\n• Tracking deliveries\n\nWhat would you like to do?";
}

return [{ json: { replyText, senderId: $('Normalize Intent').first().json.senderId } }];

// Branch 2: Product Inquiry
// In production, this queries Google Sheets. Here we return a structured reply.
const messageText = $('Normalize Intent').first().json.messageText;

const replyText = `Thanks for your interest! Let me look into that for you.

Based on your message: "${messageText}"

Here are some options from our catalog:

🔍 I'm searching our products now...

(In production, this node queries Google Sheets Products tab and returns matching items with prices, sizes, and availability.)

Would you like to:
• See a specific category?
• Filter by size or color?
• Get style recommendations?`;

return [{ json: { replyText, senderId: $('Normalize Intent').first().json.senderId } }];

// Branch 3: FAQ
// In production, this queries Google Sheets FAQ tab by keyword matching.
const messageText = $('Normalize Intent').first().json.messageText;

const replyText = `Great question! Let me find that for you.

(In production, this node searches the FAQ tab in Google Sheets using keyword matching against your message.)

In the meantime, here are our most common topics:
• Shipping: Standard 5-7 business days, Express 2-3 days
• Returns: 30-day return policy, unworn with tags
• Sizing: Check our size guide for measurements
• Payment: Visa, Mastercard, PayPal, Apple Pay

Does this help? If not, I can connect you with our team!`;

return [{ json: { replyText, senderId: $('Normalize Intent').first().json.senderId } }];

// Branch 4: Order Create
// In production, this starts a multi-turn conversation using AI Agent with memory.
const messageText = $('Normalize Intent').first().json.messageText;

const replyText = `I'd love to help you place an order! 🛒

To get started, I'll need a few details:

1️⃣ Which product would you like? (name or describe it)
2️⃣ What size?
3️⃣ What color?
4️⃣ How many?

You can provide all at once or I'll ask step by step.

(In production, this uses an AI Agent with conversation memory to collect: product, size, color, quantity, name, and email, then saves a Draft order to Google Sheets.)`;

return [{ json: { replyText, senderId: $('Normalize Intent').first().json.senderId } }];

// Branch 5: Order Tracking
const messageText = $('Normalize Intent').first().json.messageText;

// Try to extract order number from message
const orderMatch = messageText.match(/ORD-[\w-]+/i);
let replyText = '';

if (orderMatch) {
  const orderId = orderMatch[0].toUpperCase();
  replyText = `Let me look up order ${orderId} for you... 📦\n\n(In production, this searches the Tracking tab in Google Sheets by Order_ID and returns: status, carrier, tracking number, shipped date, and estimated delivery.)\n\nIf I can't find tracking info, it may mean:\n• The order hasn't shipped yet\n• The order number has a typo\n\nWould you like me to check with a different order number or your email address?`;
} else {
  replyText = `I'd be happy to check your order status! 📦\n\nCould you provide your:\n• Order number (starts with ORD-), or\n• Email address used for the order\n\nExample: ORD-20250120-001`;
}

return [{ json: { replyText, senderId: $('Normalize Intent').first().json.senderId } }];

// Branch 6: Human Support Handoff
// In production, this creates a support ticket in Google Sheets.
const messageText = $('Normalize Intent').first().json.messageText;

const replyText = `I understand you'd like some extra help. I'm connecting you with our team now. 🙋

I've created a support ticket for you.

(In production, a ticket is saved to the Support Tickets tab in Google Sheets with auto-assigned priority.)

Our team will reach out within:
• High priority: 2 hours
• Medium priority: 4 hours
• Low priority: 24 hours

(Business hours: Mon-Fri, 9 AM - 6 PM)

If it's urgent, you can also email: support@yourbrand.com

Is there anything else I can help with while you wait?`;

return [{ json: { replyText, senderId: $('Normalize Intent').first().json.senderId } }];

// Branch 7: Style Inquiry (NEW in v4 - checked BEFORE order_create)
// In production, this uses AI with product catalog context for personalized recommendations.
const messageText = $('Normalize Intent').first().json.messageText;

const replyText = `Great question! I'd love to help with styling! 👗✨

Based on your message: "${messageText}"

(In production, this uses an AI node with your product catalog as context to generate personalized style recommendations.)

Here are some general tips:
